import React, { useEffect, useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { getCurrentUser } from "../services/api";

function Navbar() {
  const location = useLocation();
  const navigate = useNavigate();

  const [currentUser, setCurrentUser] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      setCurrentUser(null);
      return;
    }

    const loadCurrentUser = async () => {
      try {
        const user = await getCurrentUser();
        setCurrentUser(user);
        localStorage.setItem("user", JSON.stringify(user));
      } catch (error) {
        console.error("Lỗi lấy user hiện tại:", error);
        localStorage.removeItem("token");
        localStorage.removeItem("user");
        setCurrentUser(null);
      }
    };

    loadCurrentUser();
  }, [location.pathname]);

  const isActive = (path) => {
    if (path === "/") return location.pathname === "/";
    return location.pathname.startsWith(path);
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setCurrentUser(null);
    navigate("/login");
  };

  return (
    <nav className="navbar">
      <div className="container navbar-inner">
        <Link to="/" className="logo">
          <span className="logo-mark">⚽</span>
          <span className="logo-text">
            Đặt <span className="logo-highlight">Sân Bóng</span>
          </span>
        </Link>

        <div className="nav-search">
          <input
            type="text"
            placeholder="Tìm sân bóng hoặc trận bóng..."
            readOnly
          />
        </div>

        <div className="nav-links">
          <Link className={isActive("/") ? "nav-link active" : "nav-link"} to="/">
            Trang chủ
          </Link>

          <Link
            className={isActive("/matches") ? "nav-link active" : "nav-link"}
            to="/matches"
          >
            Tìm trận
          </Link>

          <Link
            className={isActive("/fields") ? "nav-link active" : "nav-link"}
            to="/fields"
          >
            Sân bóng
          </Link>

          {currentUser && (
            <>
              <Link
                className={isActive("/my-schedule") ? "nav-link active" : "nav-link"}
                to="/my-schedule"
              >
                Lịch của tôi
              </Link>

              <Link
                className={isActive("/profile") ? "nav-link active" : "nav-link"}
                to="/profile"
              >
                Hồ sơ
              </Link>
            </>
          )}

          {currentUser?.role === "admin" && (
            <Link
              className={isActive("/admin") ? "nav-link active" : "nav-link"}
              to="/admin/bookings"
            >
              Quản lý
            </Link>
          )}
        </div>

        <div className="nav-user">
          {currentUser ? (
            <>
              <button className="nav-user-btn">
                {currentUser.username}
                {currentUser.role === "admin" ? " (admin)" : ""}
              </button>
              <button className="btn-outline nav-logout-btn" onClick={handleLogout}>
                Đăng xuất
              </button>
            </>
          ) : (
            <>
              <Link to="/login" className="btn-outline nav-auth-btn">
                Đăng nhập
              </Link>
              <Link to="/register" className="nav-user-btn nav-auth-btn">
                Đăng ký
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
